    biz = json.load(f)

rev = var_call_5TcZIYplqfrGLX85Ma4C92sg

dfb = pd.DataFrame(biz)
dfr = pd.DataFrame(rev)
if not dfr.empty:
    dfr['avg_rating'] = dfr['avg_rating'].astype(float)

weekdays = {'Monday','Tuesday','Wednesday','Thursday','Friday'}

def parse_close_minutes(hours_str):
    # hours_str is JSON string like [["Thursday","11AM–9:30PM"], ...]
    try:
        arr = json.loads(hours_str)
    except Exception:
        return False
    for day, hrs in arr:
        if day not in weekdays:
            continue
        if not isinstance(hrs, str):
            continue
        h = hrs.strip()
        if h.lower() == 'closed':
            continue
        if 'Open 24 hours' in h:
            return True
        # split ranges
        parts = re.split(r'\s*[–-]\s*', h)
        if len(parts) != 2:
            continue
        close = parts[1].strip()
        m = re.match(r'^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$', close, re.IGNORECASE)
        if not m:
            continue
        hour = int(m.group(1))
        minute = int(m.group(2) or '0')
        ampm = m.group(3).upper()
        if hour == 12:
            hour = 0
        if ampm == 'PM':
            hour += 12
        minutes = hour*60 + minute
        if minutes > 18*60:
            return True
    return False

if not dfb.empty:
    dfb['open_after_6_weekday'] = dfb['hours'].apply(parse_close_minutes)
    dfb2 = dfb[dfb['open_after_6_weekday']].copy()
else:
    dfb2 = dfb

# join with ratings
if not dfb2.empty and not dfr.empty:
    df = dfb2.merge(dfr, on='gmap_id', how='inner')
else:
    df = pd.DataFrame(columns=['name','hours','avg_rating'])

# pick top 5 by avg_rating desc
if not df.empty:
    df = df.sort_values(['avg_rating','name'], ascending=[False, True]).head(5)

out = df[['name','hours','avg_rating']].to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(out, ensure_ascii=False))

